I would like to suggest something.
The library SharpKml has the concept of "orphan", that is, "_an invalid XML element to be stored for later (re)serialization_".

So, their idea, which I believe is the Right Thing, is to "objectify" the recognized elements and present them to the application as usual, but to store the unrecognized ones "as is" for later serialization.

One downside is the behaviour desired by @hyperknot (involving GpsBabel) would be harder to achieve from within fastkml, if possible at all.

Their class `Element.cs` is, (just the relevant parts)

    using System;
    using System.Collections.Generic;
    using System.Collections.ObjectModel;
    using System.Linq;
    using System.Text;
    using System.Xml;
    using SharpKml.Base;

    namespace SharpKml.Dom
    {
        public abstract class Element
        {
            private List<XmlComponent> _attributes = new List<XmlComponent>();
            private List<Element> _children = new List<Element>();
            private Dictionary<Type, int> _childTypes = new Dictionary<Type, int>();
            private List<Element> _orphans = new List<Element>();   //////////////////////////////
            private StringBuilder _text = new StringBuilder();

            protected Element()
            {
                this.Children = new ReadOnlyCollection<Element>(_children);
                this.Namespaces = new XmlNamespaceManager(new NameTable());
            }

            /// (...)

            /// <summary>Gets invalid child Elements found during parsing.</summary>
            internal IEnumerable<Element> Orphans
            {
                get { return _orphans; }
            }

            /// (...)

            /// <summary>
            /// Stores an invalid child Element for later serialization.
            /// </summary>
            /// <param name="orphan">The Element to store for serialization.</param>
            protected internal virtual void AddOrphan(Element orphan)
            {
                if (orphan != null)
                {
                    orphan.Parent = this;
                    _orphans.Add(orphan);
                }
            }

            /// (...)
        }
    }

